#include<bits/stdc++.h>
#define sqrt mysqrt
using namespace std;
long long sqrt(long long x)
{
    long long ans=sqrtl(x);
    while(ans*ans>x)
    {
        ans--;
    }
    while((ans+1)*(ans+1)<=x)
    {
        ans++;
    }
    return ans;
}
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long x,z;
        scanf("%lld%lld",&x,&z);
        if(z%x!=0)
        {
            printf("-1\n");
            continue;
        }
        long long g=sqrt(gcd(x*x,z/x));
        if(g*g!=gcd(x*x,z/x))
        {
            printf("-1\n");
            continue;
        }
        if((z/x)%g!=0)
        {
            printf("-1\n");
            continue;
        }
        printf("%lld\n",z/x/g);
    }
    return 0;
}
